<script setup>
// Importing
import { cartStore } from "@/stores/cart";
import { ref, computed } from "vue";
import OrderSuccess from "@/components/order_success/OrderSuccessfully";
// * Variables
const cart = ref(cartStore());
const countries = ref(["Egypt", "Lebanon", "America", "Syria", "Jordan"]);
const dialog = ref(false);
// * Functions
const calcTotalPrice = computed(() => {
  let total = 0;
  cart.value.cartitems.forEach((product) => {
    const discountPrice =
      product.price - product.price * (product.discountPercentage / 100);
    total += Math.ceil(discountPrice * product.quantity);
  });
  return total;
});
</script>

