<template>
  <div class="order-success">
    <v-dialog v-model="dialog" width="50%" persistent>
      <v-card class="text-center py-7">
        <div>
          <v-icon class="check">mdi-check</v-icon>
        </div>
        <v-card-title class="font-weight-bold text-h4 text-grey-darken-1"
          >Order Placed Successfully!</v-card-title
        >
        <v-card-text class="text-subtitle-1 text-grey-darken-3"
          >Lorem ipsum, dolor sit amet consectetur adipisicing elit. Commodi
          exercitationem minima maiores temporibus maxime dignissimos aperiam,
          est ut dolor repudiandae numquam molestias harum velit asperiores hic,
          quam quos, quo esse.</v-card-text
        >
        <v-card-actions class="justify-center">
          <v-btn variant="elevated" color="blue" @click="resetData"
            >Got It!</v-btn
          >
        </v-card-actions>
      </v-card>
    </v-dialog>
  </div>
</template>

<script setup>
import { ref, onMounted, defineProps, defineEmits, watch } from "vue";
import { cartStore } from "@/stores/cart";
import { useRouter } from "vue-router";
// * Variables
const cart = cartStore();
const router = useRouter();
const emit = defineEmits(["close-popup"]);
const dialog = ref(null);
const props = defineProps({
  popup: {
    type: Boolean,
    required: true,
  },
});
onMounted(() => (dialog.value = props.popup));
watch(
  () => dialog.value,
  (newval) => {
    if (!newval) {
      setTimeout(() => {
        emit("close-popup");
      }, 200);
    }
  }
);
const resetData = function () {
  cart.resetItems();
  dialog.value = false;
  router.push({ name: "home" });
};
</script>

<style>
.check {
  width: 100px;
  height: 100px;
  border-radius: 50%;
  font-size: 76px;
  color: green;
  border: 1px solid green;
}
</style>
